// Normaliza inputs do agente — mesmo contrato do [Sameka] GET-Clientes.
const dadosIa = $input.item.json || {};

let cidade = (dadosIa.cidade || '').toString().trim();
let uf     = (dadosIa.uf     || '').toString().trim().toUpperCase();
let limite = parseInt(dadosIa.limite, 10);
if (!Number.isFinite(limite) || limite <= 0) limite = 50;
if (limite > 200) limite = 200;

// Se a IA mandar tudo num campo "query" (ex: "Birigui, SP")
if (dadosIa.query && !cidade) {
  const partes = dadosIa.query.toString().split(/,|\s-\s|-/);
  cidade = (partes[0] || '').trim();
  uf     = ((partes[1] || '').trim()).toUpperCase();
}

// Defaults defensivos
if (!cidade) cidade = 'Birigui';
if (!uf)     uf     = 'SP';

return { json: { cidade, uf, limite } };

// Une o nome da PRIMEIRA aba ao input normalizado (cidade/uf/limite)
const inputNorm = $('Normalizar Input').first().json;
const meta      = $input.first().json || {};
const sheets    = Array.isArray(meta.sheets) ? meta.sheets : [];

const sheetName = sheets[0] && sheets[0].properties && sheets[0].properties.title;
if (!sheetName) {
  return { json: { ...inputNorm, sheetName: null, _erro: 'Planilha sem abas visíveis' } };
}

return { json: { ...inputNorm, sheetName } };

// Filtra a planilha clientesSameka por cidade+UF e devolve envelope IGUAL ao GET-Clientes.
const params = $('Normalizar Input').first().json;
const cidadeIn = (params.cidade || '').toString();
const ufIn     = (params.uf     || '').toString().toUpperCase();
const limite   = parseInt(params.limite, 10) || 50;

// Util: normalize string (lower, trim, sem acento, sem pontuação redundante)
function norm(s) {
  if (s === undefined || s === null) return '';
  return s.toString()
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .replace(/\s+/g, ' ')
    .trim();
}

// Variantes aceitas para cada campo lógico
const MAP = {
  cidade:        ['nome_municipio','municipio','cidade','city'],
  uf:            ['sigla_uf','uf','estado','state'],
  cnpj:          ['cpf_cnpj','cnpj','cnpj_completo','documento'],
  razao:         ['razao_social','razaosocial','razao','empresa','nome'],
  fantasia:      ['nome_fantasia','fantasia','nomefantasia'],
  endereco:      ['endereco','endereco_completo','logradouro','rua'],
  bairro:        ['bairro'],
  cep:           ['cep'],
  telefone:      ['telefone','telefones','fone','celular'],
  email:         ['e_mail','email','e-mail','emails'],
  rede1:         ['rede social 1','rede_social_1','redesocial1','instagram'],
  rede2:         ['rede social 2','rede_social_2','redesocial2','facebook'],
  imagem:        ['imagem 1','imagem_1','imagem','foto'],
  cnae:          ['cnae','atividade','atividade_economica'],
  porte:         ['porte'],
  faturamento:   ['faturamento','faixa_faturamento'],
  notaIcp:       ['nota icp','nota_icp','notaicp','icp'],
  classifIcp:    ['classificacao icp','classificacao_icp','classificacaoicp']
};

function pick(row, logicalKey) {
  const candidates = MAP[logicalKey] || [];
  const rowKeys = Object.keys(row);
  const lookup = {};
  for (const k of rowKeys) lookup[norm(k)] = k;
  for (const cand of candidates) {
    const k = lookup[norm(cand)];
    if (k !== undefined && row[k] !== undefined && row[k] !== null && row[k] !== '') {
      return row[k];
    }
  }
  return null;
}

const todasLinhas = $input.all().map(i => i.json);
const cidadeNorm = norm(cidadeIn);

const clientes = [];
for (const row of todasLinhas) {
  const rowCidade = pick(row, 'cidade');
  const rowUf     = pick(row, 'uf');
  if (!rowCidade) continue;

  if (norm(rowCidade) !== cidadeNorm) continue;
  if (rowUf && rowUf.toString().toUpperCase().trim() !== ufIn) continue;

  // Telefones / emails / redes podem vir como string única
  const tel = pick(row, 'telefone');
  const eml = pick(row, 'email');
  const rs1 = pick(row, 'rede1');
  const rs2 = pick(row, 'rede2');
  const img = pick(row, 'imagem');

  clientes.push({
    cnpj:          pick(row, 'cnpj'),
    empresa:       pick(row, 'razao'),
    nomeFantasia:  pick(row, 'fantasia'),
    endereco:      pick(row, 'endereco'),
    bairro:        pick(row, 'bairro'),
    cidade:        rowCidade,
    uf:            rowUf || ufIn,
    cep:           pick(row, 'cep'),
    telefones:     tel ? [tel.toString()] : [],
    emails:        eml ? [eml.toString()] : [],
    redesSociais:  [rs1, rs2].filter(Boolean).map(String),
    fotos:         img ? [img.toString()] : [],
    possuiPresencaDigital: (rs1 || rs2) ? 'SIM' : 'NAO',
    natureza:      pick(row, 'porte'),
    cnae:          pick(row, 'cnae'),
    faturamento:   pick(row, 'faturamento'),
    score: {
      nota:          pick(row, 'notaIcp'),
      classificacao: pick(row, 'classifIcp'),
      descricao:     null
    },
    empresaCliente: 'SIM',
    empresaProspect: 'NAO',
    fonte: 'carteira_sameka'
  });
}

// Limite
const clientesLimitados = clientes.slice(0, limite);

return {
  json: {
    ok: clientesLimitados.length > 0,
    fonte: 'carteira_sameka',
    origem: 'rag_planilha_drive',
    cidade_consultada: cidadeIn,
    uf_consultada: ufIn,
    total: clientesLimitados.length,
    total_bruto_planilha: todasLinhas.length,
    clientes: clientesLimitados,
    error: clientesLimitados.length === 0
      ? `Nenhum cliente Sameka encontrado em ${cidadeIn}/${ufIn} na planilha clientesSameka (verifiquei ${todasLinhas.length} linhas).`
      : null
  }
};
